using System;
using System.IO;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY THIS LINE

string logDir = Path.Combine(ThisService.RootDirectory, "logs");
if (!Directory.Exists(logDir))
    Directory.CreateDirectory(logDir);

string logFile = Path.Combine(logDir, "VRisingServer.log");
if (File.Exists(logFile))
{
    DateTime now = DateTime.Now;
    string ts = $"{now.Year}-{now.Month}-{now.Day}__{now.Hour}-{now.Minute}-{now.Second}";
    string dest = Path.Combine(logDir, $"VRisingServer_{ts}.log");
    File.Move(logFile, dest, true);
}

