using System;
using System.IO;
using System.Diagnostics;
using System.Threading.Tasks;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY

// One-off Wine crash diagnostic: run the real wine command with error output ENABLED (ServiceIO uses
// WINEDEBUG=-all which silences everything), capture stderr + the game's own log. Linux/wine only.
if (!System.OperatingSystem.IsLinux())
{
    ScriptConsole.WriteLine("[wine-diag] not a Linux host; skipping.");
    return;
}

string root = ThisService.RootDirectory;
string ip = ThisService.IPAddress ?? "0.0.0.0";

string b = string.Join(" ",
    "set +e;",
    $"ROOT='{root}'; IP='{ip}';",
    "PREFIX=\"$ROOT/.wine\";",
    "OWNER=$(stat -c '%U' \"$ROOT\");",
    "RT=\"$ROOT/.tca/xdg-runtime\"; mkdir -p \"$RT\"; chmod 700 \"$RT\"; chown \"$OWNER\" \"$RT\";",
    "OUT=\"$ROOT/.tca/wine-diag.log\"; : > \"$OUT\"; chown \"$OWNER\" \"$OUT\";",
    "cd \"$ROOT\";",
    "echo \"[wine-diag] launching wine VRisingServer.exe as $OWNER (40s timeout)...\";",
    "runuser -u \"$OWNER\" -- env WINEPREFIX=\"$PREFIX\" HOME=\"$ROOT\" XDG_RUNTIME_DIR=\"$RT\" WINEARCH=win64 WINEDEBUG='fixme-all,+seh,+err' WINEDLLOVERRIDES='mscoree=;mshtml=' xvfb-run -a timeout 40 wine \"$ROOT/VRisingServer.exe\" -persistentDataPath \"$ROOT\" -bindAddress \"$IP\" -gamePort 28015 -queryPort 28016 -rconBindAddress \"$IP\" -rconPort 28017 -logFile \"./logs/VRisingServer.log\" > \"$OUT\" 2>&1;",
    "echo \"[wine-diag] wine exit=$?\";",
    "echo '===== last 120 lines of wine stderr =====';",
    "tail -120 \"$OUT\";",
    "echo '===== game log (if any) =====';",
    "tail -60 \"$ROOT/logs/VRisingServer.log\" 2>/dev/null || echo '(no game log written)';");

var psi = new ProcessStartInfo
{
    FileName = "/bin/bash",
    UseShellExecute = false,
    RedirectStandardOutput = true,
    RedirectStandardError = true,
};
psi.ArgumentList.Add("-c");
psi.ArgumentList.Add(b);

using (var p = Process.Start(psi))
{
    string outText = await p.StandardOutput.ReadToEndAsync();
    string errText = await p.StandardError.ReadToEndAsync();
    await p.WaitForExitAsync();
    string all = (outText ?? "") + "\n" + (errText ?? "");
    ScriptConsole.WriteLine(all.Length > 4000 ? all.Substring(all.Length - 4000) : all);
}

