using System;
using System.IO;
using System.Diagnostics;
using System.Threading.Tasks;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY

// Wine dependency provisioning. The script must be marked Windows (the game's OS) so the script
// DB-filter (which keys on the GAME OS) fetches it at all; we then gate on the HOST being Linux so
// winetricks only runs on the Wine path and is a no-op on native Windows hosts.
// Bound to AfterServiceCreated / AfterServiceReinstalled (runs inside the create/reinstall task, no
// start timeout) AND BeforeServiceStarted (safety net). Idempotent via a marker. Installs the VC++ /
// D3D runtimes the game needs into the wine prefix via winetricks, run as the prefix's owning user.
// winetricks creates the prefix (wineboot) if it doesn't exist yet (create-time); EnsurePrefixAsync
// at first start then reuses it. The marker is stamped by the shell after winetricks so it survives a
// cancelled/slow start.

if (!System.OperatingSystem.IsLinux())
{
    ScriptConsole.WriteLine("[wine-deps] Native Windows host â€” runtimes installed by the OS installer; skipping winetricks.");
    return;
}

string root = ThisService.RootDirectory;
string prefix = Path.Combine(root, ".wine");
string marker = Path.Combine(prefix, ".tcadmin-winedeps");

if (File.Exists(marker))
{
    ScriptConsole.WriteLine("[wine-deps] Runtimes already installed in the wine prefix.");
    return;
}

ScriptConsole.WriteLine("[wine-deps] Installing VC++/D3D runtimes into the wine prefix via winetricks (can take a few minutes)...");

// Owner is taken from the service ROOT (always present and chowned to the service user by the create's
// file-permission pass) â€” the .wine prefix may not exist yet at create-time. winetricks creates it.
string b = string.Join(" ",
    "set -e;",
    $"ROOT='{root}';",
    "PREFIX=\"$ROOT/.wine\";",
    "MARKER=\"$PREFIX/.tcadmin-winedeps\";",
    "OWNER=$(stat -c '%U' \"$ROOT\");",
    "echo \"[wine-deps] service user: $OWNER\";",
    "RT=\"$ROOT/.tca/xdg-runtime\"; mkdir -p \"$RT\"; chmod 700 \"$RT\"; chown \"$OWNER\" \"$RT\";",
    "runuser -u \"$OWNER\" -- env WINEPREFIX=\"$PREFIX\" HOME=\"$ROOT\" XDG_RUNTIME_DIR=\"$RT\" WINEDEBUG=-all WINEDLLOVERRIDES='mscoree=;mshtml=' xvfb-run -a winetricks -q vcrun2019 d3dcompiler_47;",
    "touch \"$MARKER\"; chown \"$OWNER\" \"$MARKER\";",
    "echo '[wine-deps] winetricks finished';");

var psi = new ProcessStartInfo
{
    FileName = "/bin/bash",
    UseShellExecute = false,
    RedirectStandardOutput = true,
    RedirectStandardError = true,
};
psi.ArgumentList.Add("-c");
psi.ArgumentList.Add(b);

using (var p = Process.Start(psi))
{
    string outText = await p.StandardOutput.ReadToEndAsync();
    string errText = await p.StandardError.ReadToEndAsync();
    await p.WaitForExitAsync();
    if (!string.IsNullOrWhiteSpace(outText))
        ScriptConsole.WriteLine(outText.Length > 2500 ? outText.Substring(outText.Length - 2500) : outText);
    if (!string.IsNullOrWhiteSpace(errText))
        ScriptConsole.WriteLine("[wine-deps stderr] " + (errText.Length > 1200 ? errText.Substring(errText.Length - 1200) : errText));
    ScriptConsole.WriteLine($"[wine-deps] winetricks exit code: {p.ExitCode}");
}
